import os

def print_dir_md(path):
    for root, dirs, files in os.walk(path):
        dirs[:] = [d for d in dirs if not d.startswith('.') and d != 'venv']
        for f in sorted(files):
            if f.endswith('.py'):
                print(f"* {f}")

if __name__ == "__main__":
    print_dir_md(".")
